solution_code:
#include <iostream>

int g_total { 0 };

void addToTotal(int x)
{
    g_total = g_total + x;
}

int main()
{
    int a {};
    int b {};
    int c {};
    std::cin >> a >> b >> c;

    addToTotal(a);
    addToTotal(b);
    addToTotal(c);

    std::cout << "Total: " << g_total << '\n';
    return 0;
}

