solution_code:
#include <iostream>

int g_max { -1001 };

void updateMax(int val)
{
    if (val > g_max)
        g_max = val;
}

int main()
{
    int a {};
    int b {};
    int c {};
    std::cin >> a >> b >> c;

    updateMax(a);
    updateMax(b);
    updateMax(c);

    std::cout << "Max: " << g_max << '\n';
    return 0;
}
